// RUN: objc3c -fobjc-version=3 -fobjc3-strictness=strict --emit-module SNDXM01.objcmod --emit-interface SNDXM01.obji --emit-interface-mode=text --emit-interface-format=deterministic %s
// RUN: objc3c --emit-module SNDXM01-import.objcmod --import-interface SNDXM01.obji --emit-interface SNDXM01-roundtrip.obji --emit-interface-mode=text --emit-interface-format=deterministic
// RUN: objc3c --verify-interface SNDXM01.objcmod SNDXM01-roundtrip.obji %s
// RUN: objc3c --verify-interface SNDXM01-import.objcmod SNDXM01.obji %s
__attribute__((objc_unsafe_sendable))
@interface SNDXM01UnsafeBox : NSObject
@property (nonatomic) int value;
@end

typedef id SNDXM01TaskHandle;
SNDXM01TaskHandle sndxm01_spawn(id (^work)(void) async) __attribute__((objc_task_spawn));

actor class SNDXM01Bridge : NSObject
- (SNDXM01UnsafeBox * _Nonnull)echo:(SNDXM01UnsafeBox * _Nonnull)value;
@end

id sndxm01_use_boundaries(SNDXM01Bridge *bridge, SNDXM01UnsafeBox *box) async {
    SNDXM01TaskHandle handle = sndxm01_spawn(^id(void) async {
        return box;
    });
    (void)await [bridge echo:box];
    return handle;
}
